#include <stdio.h>
#include <stdlib.h>
#include <string.h>

int compare(const void *a, const void *b) {
    int *x = (int *)a;
    int *y = (int *)b;
    if (x[1] < y[1]) return -1;
    if (x[1] > y[1]) return 1;
    return 0;
}

int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N;
        scanf("%d", &N);
        int **pouches = (int **)malloc(N * sizeof(int *));
        for (int i = 0; i < N; i++) {
            pouches[i] = (int *)malloc(3 * sizeof(int));
            scanf("%d %d %d", &pouches[i][0], &pouches[i][1], &pouches[i][2]);
        }
        qsort(pouches, N, sizeof(int *), compare);
        long long ans = 0;
        long long eaten = 0;
        for (int i = 0; i < N; i++) {
            long long max_eat = (pouches[i][1] - i) * 2;
            max_eat = max_eat > pouches[i][0] ? pouches[i][0] : max_eat;
            eaten += max_eat;
            ans += pouches[i][0] - max_eat;
        }
        printf("%lld\n", ans);
        for (int i = 0; i < N; i++) {
            free(pouches[i]);
        }
        free(pouches);
    }
    return 0;
}

