    int T;
    cin >> T;
    while (T--) {
        int N;
        cin >> N;
        Pouch *pouches = new Pouch[N];
        for (int i = 0; i < N; i++) {
            cin >> pouches[i].V >> pouches[i].U >> pouches[i].L;
        }
        sort(pouches, pouches + N, compare);
        long long ans = 0;
        long long eaten = 0;
        for (int i = 0; i < N; i++) {
            long long max_eat = (pouches[i].U - i) * 2;
            max_eat = max_eat > pouches[i].V ? pouches[i].V : max_eat;
            eaten += max_eat;
            ans += pouches[i].V - max_eat;
